import { NextRequest, NextResponse } from "next/server";

import {
  exchangeGithubCodeForAccessToken,
  fetchGithubUserProfile,
  GithubOAuthError,
} from "@/lib/auth/github-oauth";
import { issuePlatformSession } from "@/lib/auth/platform-session";
import type { ApiErrorResponse } from "@skynet/sdk";

interface GithubCallbackResponse {
  accessToken: string;
  tokenType: "Bearer";
  expiresIn: "1h";
  user: {
    sub: string;
    username: string;
    provider: "github";
    githubId: number;
  };
}

export const runtime = "nodejs";

function errorResponse(
  status: number,
  code: string,
  message: string,
): NextResponse<ApiErrorResponse> {
  return NextResponse.json(
    { error: { code, message } },
    {
      status,
    },
  );
}

export async function GET(request: NextRequest): Promise<NextResponse> {
  const githubAuthError = request.nextUrl.searchParams.get("error");
  if (githubAuthError) {
    const description =
      request.nextUrl.searchParams.get("error_description") ??
      "GitHub OAuth authorization was rejected.";
    return errorResponse(400, "GITHUB_OAUTH_DENIED", description);
  }

  const code = request.nextUrl.searchParams.get("code");
  if (!code) {
    return errorResponse(400, "BAD_REQUEST", "`code` query parameter is required.");
  }

  try {
    const githubAccessToken = await exchangeGithubCodeForAccessToken(code);
    const githubUser = await fetchGithubUserProfile(githubAccessToken);

    const platformSub = `github:${githubUser.id}`;
    const issuedSession = await issuePlatformSession({
      sub: platformSub,
      username: githubUser.login,
      role: "engineer",
      provider: "github",
      githubId: githubUser.id,
    });

    const responseBody: GithubCallbackResponse = {
      accessToken: issuedSession.accessToken,
      tokenType: issuedSession.tokenType,
      expiresIn: issuedSession.expiresIn,
      user: {
        sub: platformSub,
        username: githubUser.login,
        provider: "github",
        githubId: githubUser.id,
      },
    };

    const response = NextResponse.json(responseBody, { status: 201 });
    response.cookies.set(issuedSession.sessionCookie);

    return response;
  } catch (error) {
    if (error instanceof GithubOAuthError) {
      return errorResponse(error.status, error.code, error.message);
    }

    const message =
      error instanceof Error ? error.message : "GitHub OAuth callback failed.";

    return errorResponse(500, "SERVER_MISCONFIGURED", message);
  }
}

const GITHUB_ACCESS_TOKEN_URL = "https://github.com/login/oauth/access_token";
const GITHUB_USER_URL = "https://api.github.com/user";

interface GithubAccessTokenResponse {
  access_token?: string;
  error?: string;
  error_description?: string;
}

interface GithubUserResponse {
  id?: number;
  login?: string;
  name?: string | null;
  email?: string | null;
}

export interface GithubUserProfile {
  id: number;
  login: string;
  name: string | null;
  email: string | null;
}

export class GithubOAuthError extends Error {
  readonly code: string;
  readonly status: number;

  constructor(code: string, message: string, status: number) {
    super(message);
    this.code = code;
    this.status = status;
  }
}

function parseObject(value: unknown): Record<string, unknown> | null {
  if (!value || typeof value !== "object") {
    return null;
  }

  return value as Record<string, unknown>;
}

function getGithubClientCredentials(): {
  clientId: string;
  clientSecret: string;
} {
  const clientId = process.env.GITHUB_CLIENT_ID;
  const clientSecret = process.env.GITHUB_CLIENT_SECRET;

  if (!clientId || !clientSecret) {
    throw new GithubOAuthError(
      "SERVER_MISCONFIGURED",
      "GitHub OAuth requires GITHUB_CLIENT_ID and GITHUB_CLIENT_SECRET.",
      500,
    );
  }

  return { clientId, clientSecret };
}

async function readJsonBody(response: Response): Promise<unknown> {
  try {
    return await response.json();
  } catch {
    return null;
  }
}

function parseGithubAccessTokenResponse(
  body: unknown,
): GithubAccessTokenResponse | null {
  const object = parseObject(body);
  if (!object) {
    return null;
  }

  return {
    access_token:
      typeof object.access_token === "string" ? object.access_token : undefined,
    error: typeof object.error === "string" ? object.error : undefined,
    error_description:
      typeof object.error_description === "string"
        ? object.error_description
        : undefined,
  };
}

function parseGithubUserResponse(body: unknown): GithubUserResponse | null {
  const object = parseObject(body);
  if (!object) {
    return null;
  }

  return {
    id: typeof object.id === "number" ? object.id : undefined,
    login: typeof object.login === "string" ? object.login : undefined,
    name:
      typeof object.name === "string" || object.name === null
        ? object.name
        : undefined,
    email:
      typeof object.email === "string" || object.email === null
        ? object.email
        : undefined,
  };
}

export async function exchangeGithubCodeForAccessToken(
  code: string,
): Promise<string> {
  const { clientId, clientSecret } = getGithubClientCredentials();

  const response = await fetch(GITHUB_ACCESS_TOKEN_URL, {
    method: "POST",
    headers: {
      accept: "application/json",
      "content-type": "application/json",
      "user-agent": "skynet-web-auth",
    },
    body: JSON.stringify({
      client_id: clientId,
      client_secret: clientSecret,
      code,
    }),
  });

  const body = parseGithubAccessTokenResponse(await readJsonBody(response));
  if (!response.ok) {
    throw new GithubOAuthError(
      "GITHUB_OAUTH_EXCHANGE_FAILED",
      "GitHub OAuth token exchange failed.",
      502,
    );
  }

  if (!body) {
    throw new GithubOAuthError(
      "GITHUB_OAUTH_EXCHANGE_FAILED",
      "GitHub OAuth token exchange returned an invalid response.",
      502,
    );
  }

  if (body.error) {
    if (body.error === "bad_verification_code") {
      throw new GithubOAuthError(
        "INVALID_GITHUB_OAUTH_CODE",
        body.error_description ?? "GitHub OAuth code is invalid or expired.",
        401,
      );
    }

    if (body.error === "incorrect_client_credentials") {
      throw new GithubOAuthError(
        "SERVER_MISCONFIGURED",
        "GitHub OAuth client credentials are invalid.",
        500,
      );
    }

    throw new GithubOAuthError(
      "GITHUB_OAUTH_EXCHANGE_FAILED",
      body.error_description ?? "GitHub OAuth token exchange failed.",
      502,
    );
  }

  if (!body.access_token) {
    throw new GithubOAuthError(
      "GITHUB_OAUTH_EXCHANGE_FAILED",
      "GitHub OAuth token exchange did not return an access token.",
      502,
    );
  }

  return body.access_token;
}

export async function fetchGithubUserProfile(
  githubAccessToken: string,
): Promise<GithubUserProfile> {
  const response = await fetch(GITHUB_USER_URL, {
    method: "GET",
    headers: {
      accept: "application/vnd.github+json",
      authorization: `Bearer ${githubAccessToken}`,
      "user-agent": "skynet-web-auth",
    },
  });

  if (!response.ok) {
    throw new GithubOAuthError(
      "GITHUB_USER_FETCH_FAILED",
      "Failed to load GitHub user profile.",
      502,
    );
  }

  const body = parseGithubUserResponse(await readJsonBody(response));
  if (!body?.id || !body.login) {
    throw new GithubOAuthError(
      "GITHUB_USER_FETCH_FAILED",
      "GitHub user profile response is invalid.",
      502,
    );
  }

  return {
    id: body.id,
    login: body.login,
    name: body.name ?? null,
    email: body.email ?? null,
  };
}

import type { JWTPayload } from "jose";

import { signAccessToken } from "./jwt";
import { buildSessionCookie, type SessionCookie } from "./session";

export interface IssuedPlatformSession {
  accessToken: string;
  tokenType: "Bearer";
  expiresIn: "1h";
  sessionCookie: SessionCookie;
}

export async function issuePlatformSession(
  payload: JWTPayload,
): Promise<IssuedPlatformSession> {
  const accessToken = await signAccessToken(payload);

  return {
    accessToken,
    tokenType: "Bearer",
    expiresIn: "1h",
    sessionCookie: buildSessionCookie(accessToken),
  };
}

import { NextRequest, NextResponse } from "next/server";

import { issuePlatformSession } from "@/lib/auth/platform-session";
import type { ApiErrorResponse } from "@skynet/sdk";

interface TokenRequestBody {
  sub?: string;
  username?: string;
  role?: "engineer" | "pm" | "designer" | "operator";
}

interface TokenResponse {
  accessToken: string;
  tokenType: "Bearer";
  expiresIn: "1h";
}

function badRequest(message: string): NextResponse<ApiErrorResponse> {
  return NextResponse.json(
    { error: { code: "BAD_REQUEST", message } },
    { status: 400 },
  );
}

export async function POST(request: NextRequest): Promise<NextResponse> {
  let body: TokenRequestBody;
  try {
    body = (await request.json()) as TokenRequestBody;
  } catch {
    return badRequest("Request body must be valid JSON");
  }

  if (!body.sub) {
    return badRequest("`sub` is required to issue a JWT");
  }

  try {
    const issuedSession = await issuePlatformSession({
      sub: body.sub,
      username: body.username,
      role: body.role,
    });

    const responseBody: TokenResponse = {
      accessToken: issuedSession.accessToken,
      tokenType: issuedSession.tokenType,
      expiresIn: issuedSession.expiresIn,
    };

    const response = NextResponse.json(responseBody, { status: 201 });
    response.cookies.set(issuedSession.sessionCookie);
    return response;
  } catch (error) {
    const message =
      error instanceof Error
        ? error.message
        : "Server JWT configuration is missing";

    const apiError: ApiErrorResponse = {
      error: {
        code: "SERVER_MISCONFIGURED",
        message,
      },
    };

    return NextResponse.json(apiError, { status: 500 });
  }
}

import { afterEach, describe, expect, it, vi } from "vitest";

import {
  exchangeGithubCodeForAccessToken,
  fetchGithubUserProfile,
} from "./github-oauth";

const originalGithubClientId = process.env.GITHUB_CLIENT_ID;
const originalGithubClientSecret = process.env.GITHUB_CLIENT_SECRET;

function restoreGithubEnv(): void {
  if (originalGithubClientId === undefined) {
    delete process.env.GITHUB_CLIENT_ID;
  } else {
    process.env.GITHUB_CLIENT_ID = originalGithubClientId;
  }

  if (originalGithubClientSecret === undefined) {
    delete process.env.GITHUB_CLIENT_SECRET;
  } else {
    process.env.GITHUB_CLIENT_SECRET = originalGithubClientSecret;
  }
}

describe("github oauth helpers", () => {
  afterEach(() => {
    restoreGithubEnv();
    vi.unstubAllGlobals();
    vi.restoreAllMocks();
  });

  it("exchanges authorization code for github access token", async () => {
    process.env.GITHUB_CLIENT_ID = "test-client-id";
    process.env.GITHUB_CLIENT_SECRET = "test-client-secret";

    const fetchMock = vi
      .fn()
      .mockResolvedValueOnce(
        new Response(JSON.stringify({ access_token: "gho_test_access" }), {
          status: 200,
          headers: { "content-type": "application/json" },
        }),
      );
    vi.stubGlobal("fetch", fetchMock);

    const accessToken = await exchangeGithubCodeForAccessToken("oauth-code");

    expect(accessToken).toBe("gho_test_access");
    expect(fetchMock).toHaveBeenCalledWith(
      "https://github.com/login/oauth/access_token",
      expect.objectContaining({
        method: "POST",
      }),
    );
  });

  it("returns typed error when oauth code is invalid", async () => {
    process.env.GITHUB_CLIENT_ID = "test-client-id";
    process.env.GITHUB_CLIENT_SECRET = "test-client-secret";

    const fetchMock = vi
      .fn()
      .mockResolvedValueOnce(
        new Response(
          JSON.stringify({
            error: "bad_verification_code",
            error_description: "The code passed is incorrect or expired.",
          }),
          {
            status: 200,
            headers: { "content-type": "application/json" },
          },
        ),
      );
    vi.stubGlobal("fetch", fetchMock);

    await expect(
      exchangeGithubCodeForAccessToken("invalid-code"),
    ).rejects.toMatchObject({
      code: "INVALID_GITHUB_OAUTH_CODE",
      status: 401,
    });
  });

  it("throws misconfigured error when github oauth credentials are missing", async () => {
    delete process.env.GITHUB_CLIENT_ID;
    delete process.env.GITHUB_CLIENT_SECRET;

    await expect(
      exchangeGithubCodeForAccessToken("oauth-code"),
    ).rejects.toMatchObject({
      code: "SERVER_MISCONFIGURED",
      status: 500,
    });
